const results = [];

for (const item of items) {
  const input = item.json;
  const pages = input.data || input.pages || [input.page || input];
  const pagesArray = Array.isArray(pages) ? pages : [pages];

  for (const page of pagesArray) {
    const text = page.text || "";

    const vknMatch = text.match(/VERGİ KİMLİK NUMARASI\s+(\d+)/i);
    const vkn = vknMatch ? vknMatch[1] : null;

    const tcknMatch = text.match(/\(\s*T\.C\. Kimlik No\s*\)/i);
    const tckn = tcknMatch ? vkn : null;

    const soyadiMatch = text.match(/SOYADI\s*\(UNVANI\)\s*(.+)/i);
    const soyadi = soyadiMatch ? soyadiMatch[1].trim() : null;

    const adiMatch = text.match(/ADI\s*(.+)/i);
    let adi = adiMatch ? adiMatch[1].trim() : null;
    if (soyadi && adi && soyadi === adi) adi = null;

    const toplamMatch = text.match(/TOPLAM\s*([\d.,]+)/i);
    const toplamTutar = toplamMatch
      ? parseFloat(toplamMatch[1].replace(/\./g, "").replace(",", "."))
      : null;

    // استخراج TUR من Ana Vergi Kodu
    const anaVergiMatch = text.match(/Ana Vergi Kodu\s+\d+\s+(.+)/i);
    const tur = anaVergiMatch ? anaVergiMatch[1].trim() : null;

    // استخراج VADE_TARIHI بالتعديل الجديد
    const vadeMatch = text.match(/(VADESİ|VADE TARİHİ)[^\d]*(\d{2}[./]\d{2}[./]\d{4})/i);
    const vadeTarihi = vadeMatch ? vadeMatch[2] : null;

    if (!vkn && !soyadi && !adi && !toplamTutar && !tur) {
      continue;
    }

    results.push({
      VKN: vkn,
      TCKN: tckn,
      SOYADI_UNVANI: soyadi,
      ADI: adi,
      TOPLAM_TUTAR: toplamTutar,
      TUR: tur,
      VADE_TARIHI: vadeTarihi,
      _fileIndex: items.indexOf(item),
    });
  }
}

// إزالة التكرار
const seen = new Set();
const uniqueResults = [];
for (const row of results) {
  const key = `${row.VKN}-${row.TOPLAM_TUTAR}-${row.TUR}`;
  if (!seen.has(key)) {
    uniqueResults.push(row);
    seen.add(key);
  }
}

return uniqueResults.map(r => ({ json: r }));

