return items.map(item => {
  // قائمة الأشهر التركية بالأحرف الكبيرة مع دعم الحروف التركية
  const months = [
    "OCAK", "ŞUBAT", "ŞUBAT", "MART", "NİSAN", "NISAN", "MAYIS", "HAZİRAN", "HAZIRAN",
    "TEMMUZ", "AĞUSTOS", "AĞUSTOS", "EYLÜL", "EYLUL", "EKİM", "EKIM", "KASIM", "ARALIK"
  ];

  // دمج الأشهر في تعبير منتظم (يدعم بعض أخطاء الترميز الشائعة)
  const monthsRegex = months.join("|");

  // تعبير منتظم لاستخراج اسم الشركة والشهر والسنة ونوع الضريبة وTHK
  const regex = new RegExp(
    `^(.+?)\\s+(${monthsRegex})\\s+(20\\d{2})\\s+([A-ZÇĞİÖŞÜ]+)(?:\\s+THK)?\\.pdf$`,
    'iu'
  );

  let originalName = item.json.name;
  let match = originalName.match(regex);

  let companyName = "";
  let month = "";
  let year = "";
  let taxType = "";

  if (match) {
    companyName = match[1].trim();
    month = match[2].toUpperCase();
    year = match[3];
    taxType = match[4].toUpperCase();
  } else {
    // fallback: لو لم يتطابق النمط
    companyName = originalName.replace(/\.[^/.]+$/, "");
